// CLX Copilot Whisper Transcribe v1 — Validate + size check
const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const binaryData = $input.item.binary || {};

const token = body.token || null;
const masterToken = process.env.MARY_MASTER_TOKEN || 'TODO_SET_MARY_MASTER_TOKEN';
if (!token || masterToken === 'TODO_SET_MARY_MASTER_TOKEN' || token !== masterToken) {
  return { json: { _unauthorized: true, error: 'admin token required' } };
}

// Locate the audio file in the multipart payload
const audioKey = Object.keys(binaryData)[0] || null;
const audio = audioKey ? binaryData[audioKey] : null;
if (!audio) {
  return { json: { _empty: true, error: 'audio file required' } };
}

// Validate format + size
const mime = (audio.mimeType || '').toLowerCase();
const allowedMime = ['audio/mpeg','audio/mp3','audio/wav','audio/x-wav','audio/mp4','audio/m4a','audio/webm','audio/ogg'];
if (allowedMime.indexOf(mime) === -1 && !/^audio\//.test(mime)) {
  return { json: { _empty: true, error: 'unsupported audio format: ' + mime } };
}

const sizeBytes = audio.fileSize || (audio.data ? Math.ceil(audio.data.length * 3 / 4) : 0);
if (sizeBytes > 25 * 1024 * 1024) {
  return { json: { _empty: true, error: 'audio exceeds 25MB Whisper limit' } };
}

return { json: { _authorized: true, audioKey, mime, sizeBytes } };

// CLX Copilot Whisper Transcribe v1 — Build response
const resp = $input.item.json || {};
const text = resp.text || null;
if (!text) {
  return { json: { ok: false, text: null, error: resp.error || resp.message || 'Whisper returned no text' } };
}
return { json: { ok: true, text, error: null } };
